import React, { Component } from 'react';
import Spinner from 'react-bootstrap/Spinner';
export class AddressSearch extends Component {
  constructor(props) {
    super(props);
    this.state = { query: '', data: [], loading: true };
  }

  componentDidMount(q) {
    this.populateWeatherData(q);
  }

  static renderForecastsTable(documents) {
    return (
      <table className='table table-striped' aria-labelledby="tabelLabel">
        <tbody>
          {documents.map(document =>
            <tr key={document.datetime}>
              <td>
                <a href={document.url} alt={document.title}><div dangerouslySetInnerHTML={{ __html: document.title }} /></a>
                <div dangerouslySetInnerHTML={{ __html: document.contents }} />
                <p>{document.datetime}</p>
              </td>
            </tr>
          )}
        </tbody>
      </table>
    );
  }

  handleChange(e) {
    this.setState({ [e.target.name]: e.target.value })
  }

  render() {
    let contents = this.state.loading ? <div><Spinner animation="border" role="status"><span className="sr-only">Loading...</span></Spinner></div>
      : AddressSearch.renderForecastsTable(this.state.data.documents);

    return (
      <div>
        <h1>주소 검색</h1>
        <p>
          주소를 지도 위에 정확하게 표시하기 위해 해당 주소의 좌표 정보를 제공하는 API로 주소에 해당하는 지번 주소, 도로명 주소, 좌표, 우편번호, 빌딩명 등의 다양한 정보를 함께 제공합니다. 애플리케이션(이하 앱) REST API 키를 헤더에 담아 GET으로 요청합니다. 원하는 검색어와 함께 결과 형식 파라미터의 값을 선택적으로 추가할 수 있습니다. 이 API는 지번 주소, 도로명 주소 모두 지원합니다. 응답은 JSON과 XML 형식을 지원합니다.
            </p>
        <p>curl -v -X GET "https://dapi.kakao.com/v2/local/search/address.json" \
        --data-urlencode "query=전북 삼성동 100" \
-H "Authorization: KakaoAK REST_API_KEY"</p>

          <form className="form-signin" onSubmit={this.populateWeatherData(this.state.query)}>
            <input type="text" id="inputquery" className="form-control" placeholder="query" required="required" name="query" onChange={this.handleChange} />
            <button className="btn btn-lg btn-primary btn-block" type="submit">Sign in</button>
          </form>
        

        {contents}

      </div>
    );
  }
  async populateWeatherData(q) {
    const response = await fetch('/api/kakao/daumSearch/web?query=' + q);
    const data = await response.json();
    this.setState({ data: data, loading: false });
  }
}
